#include<bits/stdc++.h>
using namespace std;

const int N = 5e3 + 5;
const int M = 2e5 + 5;

int fa[N];

int find(int x)
{
    return x == fa[x] ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y)
{
    fa[find(x)] = find(y);
}

struct Edge
{
    int u, v, w;
    void read()
    {
        cin >> u >> v >> w;
    }
}e[M];

bool cmp(Edge x, Edge y)
{
    return x.w < y.w;
}

int main()
{
    int n, m, ans = 0, cnt = 0;
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        fa[i] = i;
    for(int i = 1; i <= m; i++)
        e[i].read();
    sort(e + 1, e + m + 1, cmp);
    for(int i = 1; i <= m; i++)
    {
        int u = e[i].u, v = e[i].v, w = e[i].w;
        if(find(u) != find(v))
        {
            ++cnt;
            ans += w;
            merge(u, v);
        }
    }
    if(cnt < n - 1) cout << "orz";
    else cout << ans;
}
